class Animal:
    def __init__(self, nome):
        self.nome = nome

    def falar(self):
        return 'Animal fala'

class Cachorro(Animal):
    def falar(self):
        return 'Au au!'

class Gato(Animal):
    def falar(self):
        return 'Miau!'

c = Cachorro('Rex')
g = Gato('Mimi')
print(c.falar())
print(g.falar())
